package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testIsLineBreakWithNullCharacter() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);
        Boolean result = (Boolean) isLineBreakMethod.invoke(null, (Character) null);
        assertFalse(result);
    }

    @Test
    public void testIsLineBreakWithChar_CR() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);
        Boolean result = (Boolean) isLineBreakMethod.invoke(null, Character.valueOf('\r'));
        assertTrue(result);
    }

    @Test
    public void testIsLineBreakWithChar_LF() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);
        Boolean result = (Boolean) isLineBreakMethod.invoke(null, Character.valueOf('\n'));
        assertTrue(result);
    }

    @Test
    public void testIsLineBreakWithCharOther() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);
        Boolean result = (Boolean) isLineBreakMethod.invoke(null, Character.valueOf('a'));
        assertFalse(result);
    }
}
